import { ProfileInfoUpdate } from './ProfileInfoUpdate';
import { Alert, Typography } from '@mui/material';
import EditIcon from '@mui/icons-material/Edit';
import { IsProfileComplete } from '@/utils/token';
import { PageContainer } from '@/components/PageContainer';

interface ProfileUpdateProps {
    profileId?: string;
}

export const ProfileUpdate: React.FunctionComponent<ProfileUpdateProps> = ({ profileId }) => {
    const profileComplete = IsProfileComplete();

    return (
        <PageContainer
            icon={<EditIcon color="primary" />}
            title={profileId ? 'Edit profile' : 'Edit my profile'}
            subtitle={profileId
                ? 'Update this user\u2019s profile.'
                : 'Update your alumni profile information and visibility settings.'}
        >
            {!profileComplete && (
                <Alert severity="info" sx={{ mb: 2 }}>
                    <Typography variant="subtitle2" sx={{ fontWeight: 600, mb: 0.5 }}>
                        Please complete your profile
                    </Typography>
                    <Typography variant="caption">
                        You can access the rest of the website only when your profile is complete.
                    </Typography>
                </Alert>
            )}
            <ProfileInfoUpdate profileId={profileId} />
        </PageContainer>
    );
}
