import React from 'react'
import { Button, Checkbox, Chip, Divider, FormControl, FormControlLabel, FormGroup, InputLabel, MenuItem, Select, SelectChangeEvent, Stack, TextField, Typography } from '@mui/material'
import List from '@mui/material/List'
import ListItem from '@mui/material/ListItem'
import ListItemText from '@mui/material/ListItemText'
import ListItemAvatar from '@mui/material/ListItemAvatar'
import Avatar from '@mui/material/Avatar'
import { PageCard } from '@/components/PageCard'
import { StatusMessage } from '@/components/StatusMessage'
import ContactMailIcon from '@mui/icons-material/ContactMail'
import WorkIcon from '@mui/icons-material/Work'
import SchoolIcon from '@mui/icons-material/School'
import BadgeIcon from '@mui/icons-material/Badge';
import { UpdateProfilePayload, CastedUpdateProfilePayload } from '@/types/profile.types'
import { CallStatus, Gender, ProfileType, SchoolData, Validator } from '@/types/api.types'
import { Schools } from '@/constants/StaticData'
import { GetUserId, SetProfileComplete } from '@/utils/token'
import { useProfilesStore } from '@/store';
import { ApiGlobalStateManager } from '@/lib/api-state';
import { ProfileServices, ProfileServicesError } from '@/api';
import { submitButtonStyle } from '@/constants/ThemeConstants';
import { Pathname } from '@/constants/Routes';
import { useNavigate, useSearch } from '@tanstack/react-router';
import { IsProfileComplete } from '@/utils/token';
import { getHttpStatus } from '@/utils/apiError';
import { AppDialog } from '@/components/ui/AppDialog';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';

interface ProfileInfoUpdateProps {
    profileId?: string;
}

export const ProfileInfoUpdate: React.FunctionComponent<ProfileInfoUpdateProps> = ({ profileId }) => {
    const hiddenText = '[Visible to you only]'
    const visibleText = '[Visible to all members]'
    const { profileState, setProfileState } = useProfilesStore();
    const [formData, setFormData] = React.useState<UpdateProfilePayload>({} as UpdateProfilePayload);
    const [isFormValid, setIsFormValid] = React.useState<boolean>(false);
    const [isSubmitted, setIsSubmitted] = React.useState<boolean>(false);
    const [selectedSchools, setSelectedSchools] = React.useState<SchoolData[]>([]);
    const [showSuccessDialog, setShowSuccessDialog] = React.useState<boolean>(false);

    const userId = GetUserId();

    const navigate = useNavigate();
    const search = useSearch({ strict: false }) as Record<string, string>;
    // Capture once on mount so a re-render after SetProfileComplete() doesn't flip this to true.
    const wasIncompleteOnMountRef = React.useRef<boolean>(!IsProfileComplete());

    // Lock core fields once the current user has stamped a self-edit.
    // Bulk-migrated profiles carry a legacy modifiedBy that won't equal `userId`,
    // so a userId match is sufficient — no separate "migration" heuristic needed.
    const isEditingOwnProfile = !profileId;
    const modifiedBy = profileState.data?.modifiedBy;
    const hasSelfEdited = isEditingOwnProfile && !!userId && modifiedBy === userId;
    const coreFieldsLocked = hasSelfEdited;

    const handleSecondarySchoolIdsRemove = (schoolToDelete: SchoolData) => {
        const newSecondarySchoolIds = selectedSchools.filter((selectedSchools) => selectedSchools.UniqueId !== schoolToDelete.UniqueId);
        setSelectedSchools(newSecondarySchoolIds);
        const uniqueIds = newSecondarySchoolIds.map((school) => school.UniqueId);
        setFormData({ ...formData, otherJnvIds: uniqueIds });
        validateForm();
    };

    const handleSecondarySchoolIdsAdd = (schoolToAdd: SchoolData) => {
        if (!selectedSchools.find((selectedSchools) => selectedSchools.UniqueId === schoolToAdd.UniqueId)) {
            const newSecondarySchoolIds = [...selectedSchools, schoolToAdd];
            setSelectedSchools(newSecondarySchoolIds);
            const uniqueIds = newSecondarySchoolIds.map((school) => school.UniqueId);
            setFormData({ ...formData, otherJnvIds: uniqueIds });
        }
        validateForm();
    };

    const populateSelectedSchools = (profileData: any) => {
        if (profileData?.otherJnvIds) {
            const newSecondarySchools = profileData.otherJnvIds.map((uniqueId: number) => Schools.find((school) => school.UniqueId === uniqueId) as SchoolData);
            setSelectedSchools(newSecondarySchools);
        }
    }

    React.useEffect(() => {
        if (profileId) {
            // Admin editing another profile
            ProfileServices.GetAdminProfileById(profileId).then((response) => {
                if (response.data.status === 200 && response.data.result) {
                    setFormData(CastedUpdateProfilePayload(response.data.result));
                    populateSelectedSchools(response.data.result);
                }
            });
        } else if (profileState.status === CallStatus.Success && profileState.data.id) {
            setFormData(CastedUpdateProfilePayload(profileState.data));
            populateSelectedSchools(profileState.data);
        }
        else {
            ApiGlobalStateManager(ProfileServices.GetProfile(), setProfileState).then(() => {
                if (profileState.data) {
                    populateSelectedSchools(profileState.data);
                }
            });
        }
    }, [profileId]);

    React.useEffect(() => {
        if (!profileId && profileState.data?.id) {
            setFormData(CastedUpdateProfilePayload(profileState.data));
        }
    }, [formData.id, profileState.data, profileId])

    // Re-validate whenever form data changes so the Update button reflects the latest state.
    // Inline validateForm() calls in onChange handlers see stale formData (React state is async),
    // so we rely on this effect for accurate gating.
    React.useEffect(() => {
        validateForm();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [formData, profileId]);

    // Validate the Update Profile Payload
    const validateForm = () => {
        // Admins editing other users can submit partial updates.
        if (profileId) {
            setIsFormValid(true);
            return true;
        }

        const isGeneralInfoValid: boolean = Validator.IsText(formData.name)
            && Validator.IsPhone(formData.phone)
            && Validator.IsText(formData.location)
            && Validator.IsText(formData.university)
            && Validator.IsText(formData.degree)

        const isAlumniInfoValid: boolean = isGeneralInfoValid
            && (formData.entryClass ?? 0) > 0
            && (formData.entryYear ?? 0) > 0
            && (formData.exitClass ?? 0) > (formData.entryClass ?? 0)
            && (formData.exitYear ?? 0) > (formData.entryYear ?? 0);

        const isStudentInfoValid: boolean = isGeneralInfoValid
            && (formData.entryClass ?? 0) > 0
            && (formData.entryYear ?? 0) > 0
            && (formData.exitClass ?? 0) === 0
            && (formData.exitYear ?? 0) === 0;

        const isStaffInfoValid: boolean = isGeneralInfoValid
            && Validator.IsText(formData.organisation)
            && Validator.IsText(formData.jobTitle);

        if (formData.profileType === ProfileType.Student) {
            setIsFormValid(isStudentInfoValid);
            return isGeneralInfoValid;
        }
        else if (formData.profileType === ProfileType.Staff) {

            setIsFormValid(isStaffInfoValid);
            return isStaffInfoValid;
        }
        else if (formData.profileType === ProfileType.Alumni) {
            setIsFormValid(isAlumniInfoValid);
            return isAlumniInfoValid;
        }
        else {
            setIsFormValid(isGeneralInfoValid);
            return isGeneralInfoValid;
        }
    }

    const handleProfileTypeChange = (e: SelectChangeEvent<ProfileType>) => {
        if (e.target.value === ProfileType.Student) {
            setFormData({ ...formData, profileType: e.target.value, isStudying: true, isWorking: false, exitClass: 0, exitYear: 0, university: '', degree: '', organisation: '', jobTitle: '' });
        }
        else if (e.target.value === ProfileType.Staff) {
            setFormData({ ...formData, profileType: e.target.value, isStudying: false, isWorking: true, exitClass: 0, exitYear: 0, organisation: 'Navodaya Vidyala Samiti' });
        }
        else {
            setFormData({ ...formData, profileType: e.target.value as ProfileType });
        }
    }

    // Handle Form Submit
    const handleFormSubmit = (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        if (validateForm()) {
            setIsSubmitted(true);
            if (profileId) {
                // Admin partial update — strip fields that would fail server validation
                // (empty Email/Photo would hit [EmailAddress]/[Url]). The backend treats
                // omitted fields as "leave unchanged" (JSON Merge Patch semantics).
                const adminPayload: UpdateProfilePayload = { ...formData };
                delete adminPayload.id;
                if (!adminPayload.email) delete adminPayload.email;
                if (!adminPayload.photo) delete adminPayload.photo;
                // Admin updating another user, don't update global profileState
                ProfileServices.UpdateProfileAdmin(profileId, adminPayload)
                    .then((response) => {
                        // Create a temporary status state for the UI
                        const statusState: any = {
                            status: response.status === 200 ? CallStatus.Success : CallStatus.Failure,
                            httpStatus: response.status,
                            data: response.data.result,
                            timestamp: new Date()
                        };
                        setProfileState(statusState);
                    })
                    .catch((error) => {
                        const statusState: any = {
                            status: CallStatus.Failure,
                            httpStatus: getHttpStatus(error) || 500,
                            data: {},
                            timestamp: new Date()
                        };
                        setProfileState(statusState);
                    });
            } else {
                ApiGlobalStateManager(ProfileServices.UpdateProfile(formData), setProfileState).then(() => {
                    SetProfileComplete();
                    window.dispatchEvent(new Event('auth-changed'));
                    // First-time profile completion: honor the redirect carried over from login.
                    if (wasIncompleteOnMountRef.current) {
                        const redirect = search?.redirect || Pathname.Root;
                        navigate({ to: redirect, replace: true });
                    }
                });
            }
        }
    }

    // Show success dialog after a successful update (admin edits and returning users).
    // First-time profile completion is excluded so the redirect from login can run instead.
    React.useEffect(() => {
        if (
            isSubmitted &&
            !wasIncompleteOnMountRef.current &&
            profileState.status === CallStatus.Success
        ) {
            setShowSuccessDialog(true);
        }
    }, [isSubmitted, profileState.status, profileId]);

    const handleSuccessDialogClose = () => {
        setShowSuccessDialog(false);
        if (!profileId) {
            navigate({ to: Pathname.Profile as string });
        }
    };

    return (
        <PageCard>
            {formData.id ? (
                <form onSubmit={handleFormSubmit} onChange={validateForm}>
                    <Stack direction='column' spacing={2} sx={{ my: 2 }}>                        
                        {coreFieldsLocked && (
                            <Typography variant="caption" color="text.secondary">
                                Name, Gender, Entry JNV, and Entry Year are locked. Contact an admin to update these fields.
                            </Typography>
                        )}
                    </Stack>
                    <List>
                        <ListItem>
                            <ListItemAvatar>
                                <Avatar>
                                    <BadgeIcon />
                                </Avatar>
                            </ListItemAvatar>
                            <ListItemText primary="Navodaya Info" secondary={visibleText} />
                        </ListItem>
                        <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                            <TextField
                                label="Name"
                                required
                                disabled={coreFieldsLocked}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                error={!profileId && (formData.name !== '' && formData.name !== null && (formData.name ?? '').length < 3)}
                                value={formData.name}
                            />
                            <FormControl>
                                <InputLabel id="gender" >Gender</InputLabel>
                                <Select
                                    labelId="gender"
                                    id="gender-select"
                                    value={formData.gender}
                                    label="Gender"
                                    required
                                    disabled={coreFieldsLocked}
                                    onChange={(e) => { setFormData({ ...formData, gender: e.target.value }); validateForm(); }}
                                >
                                    {Object.values(Gender).map((genderOption) => (
                                        <MenuItem key={genderOption} value={genderOption}>{genderOption}</MenuItem>
                                    ))}
                                </Select>
                            </FormControl>
                            <FormControl>
                                <InputLabel id="profileType" >Profile Type</InputLabel>
                                <Select
                                    labelId="profileType"
                                    id="profileType-select"
                                    value={formData.profileType}
                                    label="Profile type"
                                    required
                                    onChange={(e) => { handleProfileTypeChange(e); validateForm(); }}
                                >
                                    <MenuItem key={ProfileType.Alumni} value={ProfileType.Alumni}>JNV Alumni</MenuItem>
                                    <MenuItem key={ProfileType.Student} value={ProfileType.Student}>Current JNV Student</MenuItem>
                                    <MenuItem key={ProfileType.ExStaff} value={ProfileType.ExStaff}>Former JNV Staff</MenuItem>
                                    <MenuItem key={ProfileType.Staff} value={ProfileType.Staff}>Current JNV Staff</MenuItem>
                                </Select>
                            </FormControl>
                            <FormControl>
                                <InputLabel id="entryJNV" >Entry JNV</InputLabel>
                                <Select
                                    labelId="entryJNV"
                                    id="entryJNV-select"
                                    value={formData.firstJnvId}
                                    label="Entry JNV"
                                    required
                                    disabled={coreFieldsLocked}
                                    onChange={(e) => { setFormData({ ...formData, firstJnvId: Number(e.target.value) }); validateForm(); }}
                                >
                                    {Schools.map((school) => (
                                        <MenuItem key={school.UniqueId} value={school.UniqueId}>[{school.StatePrefix}] JNV {school.SchoolName}</MenuItem>
                                    ))}
                                </Select>
                            </FormControl>
                            <FormControl>
                                <InputLabel id="otherJNVs" >Other JNV</InputLabel>
                                <Select
                                    labelId="otherJNVs"
                                    id="otherJNVs-select"
                                    label="Other JNVs"
                                    value="Add other JNVs attended"
                                    onChange={(e) => { 
                                        if (e.target.value !== "Add other JNVs attended") {
                                            handleSecondarySchoolIdsAdd(Schools.find((school) => school.UniqueId === Number(e.target.value)) as SchoolData); 
                                            validateForm(); 
                                        }
                                    }}
                                >
                                    <MenuItem disabled value="Add other JNVs attended">Add other JNVs attended</MenuItem>
                                    {Schools.map((school) => (
                                        <MenuItem key={school.UniqueId} value={school.UniqueId}>[{school.StatePrefix}] JNV {school.SchoolName}</MenuItem>
                                    ))}
                                </Select>
                            </FormControl>
                            <Stack
                                sx={{
                                    display: 'flex',
                                    justifyContent: 'left',
                                    flexWrap: 'wrap',
                                }}
                            >
                                {selectedSchools.map((school) => {
                                    return (
                                        <ListItem key={school.UniqueId}>
                                            <Chip
                                                label={`${school.StatePrefix} - ${school.SchoolName}`}
                                                onDelete={() => handleSecondarySchoolIdsRemove(school)}
                                            />
                                        </ListItem>
                                    );
                                })}
                            </Stack>
                            {
                                (formData.profileType === ProfileType.Student || formData.profileType === ProfileType.Alumni) &&
                                (
                                    <FormControl>
                                        <InputLabel id="entryClass">Entry class</InputLabel>
                                        <Select
                                            labelId="entryClass"
                                            id="entryClass-select"
                                            value={(formData.entryClass ?? 0).toString()}
                                            label="Entry class"
                                            required
                                            error={!profileId && (formData.profileType === ProfileType.Student ? false : (formData.exitClass ?? 0) <= (formData.entryClass ?? 0))}
                                            onChange={(e) => { setFormData({ ...formData, entryClass: parseInt(e.target.value) }); validateForm(); }}
                                        >
                                            {
                                                Array.from(Array(12 - 6 + 1).keys()).map((i) => i + 6).map((entryClassOption) => (
                                                    <MenuItem key={entryClassOption} value={entryClassOption}>{entryClassOption}</MenuItem>
                                                ))
                                            }
                                        </Select>
                                    </FormControl>
                                )
                            }
                            {
                                formData.profileType === ProfileType.Alumni &&
                                (
                                    <FormControl>
                                        <InputLabel id="exitClass">Exit class</InputLabel>
                                        <Select
                                            labelId="exitClass"
                                            id="exitClass-select"
                                            value={(formData.exitClass ?? 0).toString()}
                                            label="Entry class"
                                            required
                                            error={!profileId && ((formData.exitClass ?? 0) <= (formData.entryClass ?? 0))}
                                            onChange={(e) => { setFormData({ ...formData, exitClass: parseInt(e.target.value) }); validateForm(); }}
                                        >
                                            {
                                                Array.from(Array(12 - 6 + 1).keys()).map((i) => i + 6).map((exitClassOption) => (
                                                    <MenuItem key={exitClassOption} value={exitClassOption}>{exitClassOption}</MenuItem>
                                                ))
                                            }

                                        </Select>
                                    </FormControl>
                                )
                            }

                            <FormControl>
                                <InputLabel id="entryYear">Entry year</InputLabel>
                                <Select
                                    labelId="entryYear"
                                    id="entryYear-select"
                                    value={(formData.entryYear ?? 0).toString()}
                                    label="Entry class"
                                    required
                                    disabled={coreFieldsLocked}
                                    error={!profileId && (formData.profileType === ProfileType.Student || formData.profileType === ProfileType.Staff ? false : (formData.exitYear ?? 0) <= (formData.entryYear ?? 0))}
                                    onChange={(e) => { setFormData({ ...formData, entryYear: parseInt(e.target.value) }); validateForm(); }}
                                >
                                    {
                                        Array.from(Array((new Date()).getFullYear() - 1985 + 1).keys()).map((i) => i + 1985).map((entryYearOption) => (
                                            <MenuItem key={entryYearOption} value={entryYearOption}>{entryYearOption}</MenuItem>
                                        ))
                                    }
                                </Select>
                            </FormControl>

                            {
                                (formData.profileType !== ProfileType.Student && formData.profileType !== ProfileType.Staff) &&
                                (
                                    <FormControl>
                                        <InputLabel id="exitYear">Exit year</InputLabel>
                                        <Select
                                            labelId="exitYear"
                                            id="exitYear-select"
                                            value={(formData.exitYear ?? 0).toString()}
                                            label="Entry class"
                                            error={!profileId && ((formData.exitYear ?? 0) <= (formData.entryYear ?? 0))}
                                            required
                                            onChange={(e) => { setFormData({ ...formData, exitYear: parseInt(e.target.value) }); validateForm(); }}
                                        >
                                            {
                                                Array.from(Array((new Date()).getFullYear() - 1985 + 1).keys()).map((i) => i + 1985).map((exitYearOption) => (
                                                    <MenuItem key={exitYearOption} value={exitYearOption}>{exitYearOption}</MenuItem>
                                                ))
                                            }
                                        </Select>
                                    </FormControl>
                                )
                            }
                        </Stack>
                        <Divider />
                        <ListItem>
                            <ListItemAvatar>
                                <Avatar>
                                    <ContactMailIcon />
                                </Avatar>
                            </ListItemAvatar>
                            <ListItemText
                                primary='Contact Info'
                                secondary={
                                    formData.isContactInfoVisible ? visibleText : hiddenText
                                }
                            />
                        </ListItem>
                        <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                            <FormControlLabel
                                control={<Checkbox checked={formData.isContactInfoVisible}
                                    onChange={(e) => { setFormData({ ...formData, isContactInfoVisible: e.target.checked }); validateForm(); }} />}
                                label="Visible to members" />
                            <TextField
                                label="Email"
                                disabled={!profileId}
                                onChange={(e) => { setFormData({ ...formData, email: e.target.value }); validateForm(); }}
                                value={formData.email || ''}
                                helperText={profileId ? "Admins can update the email address" : "Email cannot be changed by the user"}
                            />
                            <TextField
                                label="Phone"
                                placeholder="Format: 9876543210 or +123-9876543210"
                                onChange={(e) => { setFormData({ ...formData, phone: e.target.value }); validateForm(); }}
                                error={!profileId && !Validator.IsPhone(formData.phone)}
                                value={formData.phone}
                            />
                            <Typography variant="caption" color="text.secondary" sx={{ fontSize: '0.75rem', mt: 0.5, ml: 1.75 }}>
                                Indian: 10 digits (9876543210)
                                <br />
                                Abroad: +countrycode-number (+123-9876543210)
                            </Typography>
                            <TextField
                                label="Location"
                                onChange={(e) => { setFormData({ ...formData, location: e.target.value }); validateForm(); }}
                                error={!profileId && !Validator.IsText(formData.location)}
                                value={formData.location}
                            />
                        </Stack>
                        {formData.profileType && formData.profileType !== ProfileType.Student &&
                            (
                                <>
                                    <Divider />
                                    <ListItem>
                                        <ListItemAvatar>
                                            <Avatar>
                                                <SchoolIcon />
                                            </Avatar>
                                        </ListItemAvatar>
                                        <ListItemText
                                            primary='Highest Educational Info'
                                            secondary={
                                                formData.isHigherEducationInfoVisible
                                                    ? visibleText
                                                    : hiddenText
                                            }
                                        />
                                    </ListItem>
                                    <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                        <FormGroup>
                                            <FormControlLabel
                                                control={<Checkbox checked={formData.isHigherEducationInfoVisible}
                                                    onChange={(e) => { setFormData({ ...formData, isHigherEducationInfoVisible: e.target.checked }); validateForm(); }} />}
                                                label="Visible to members" />
                                            <FormControlLabel
                                                control={<Checkbox checked={formData.isStudying}
                                                    onChange={(e) => { setFormData({ ...formData, isStudying: e.target.checked }); validateForm(); }} />}
                                                label="Currently studying" />
                                        </FormGroup>
                                        <TextField
                                            label="University/College/School"
                                            onChange={(e) => { setFormData({ ...formData, university: e.target.value }); validateForm(); }}
                                            error={!profileId && !Validator.IsText(formData.university)}
                                            value={formData.university}
                                        />
                                        <TextField
                                            label="Degree/Level"
                                            onChange={(e) => { setFormData({ ...formData, degree: e.target.value }); validateForm(); }}
                                            error={!profileId && !Validator.IsText(formData.degree)}
                                            value={formData.degree}
                                        />
                                    </Stack>
                                </>)
                        }
                        {
                            formData.profileType && formData.profileType !== ProfileType.Student &&
                            (
                                <>
                                    <Divider />
                                    <ListItem>
                                        <ListItemAvatar>
                                            <Avatar>
                                                <WorkIcon />
                                            </Avatar>
                                        </ListItemAvatar>
                                        <ListItemText
                                            primary='Latest Employment Info'
                                            secondary={
                                                formData.isEmploymentInfoVisible ? visibleText : hiddenText
                                            }
                                        />
                                    </ListItem>
                                    <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                        <FormGroup>
                                            <FormControlLabel
                                                control={<Checkbox checked={formData.isEmploymentInfoVisible}
                                                    onChange={(e) => { setFormData({ ...formData, isEmploymentInfoVisible: e.target.checked }); validateForm(); }} />}
                                                label="Visible to members" />
                                            <FormControlLabel
                                                control={<Checkbox checked={formData.isWorking}
                                                    onChange={(e) => { setFormData({ ...formData, isWorking: e.target.checked }); validateForm(); }} />}
                                                label="Currently working" />
                                        </FormGroup>
                                        <TextField
                                            label="organisation"
                                            onChange={(e) => setFormData({ ...formData, organisation: e.target.value })}
                                            error={!profileId && (formData.isWorking ? !Validator.IsText(formData.organisation) : false)}
                                            value={formData.organisation}
                                        />
                                        <TextField
                                            label="Job Title"
                                            onChange={(e) => { setFormData({ ...formData, jobTitle: e.target.value }); validateForm(); }}
                                            error={!profileId && (formData.isWorking ? !Validator.IsText(formData.jobTitle) : false)}
                                            value={formData.jobTitle}
                                        />
                                    </Stack>
                                </>
                            )
                        }
                        <Divider />
                        <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                            <Button style={submitButtonStyle} disabled={!isFormValid} variant="contained" type="submit">Update</Button>
                            <StatusMessage
                                currentStatus={isSubmitted && profileState.status !== CallStatus.Success ? profileState.status : CallStatus.NotStarted}
                                notStartedMessage="Go ahead, Update your info👍"
                                successMessage=""
                                failureMessage={ProfileServicesError.UpdateProfileError(profileState.httpStatus)}
                                correlationId={profileState.correlationId}
                            />
                        </Stack>
                    </List>
                </form>
            ) : profileState.status === CallStatus.Failure ? (
                <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                    <StatusMessage
                        currentStatus={CallStatus.Failure}
                        notStartedMessage=""
                        successMessage=""
                        failureMessage={ProfileServicesError.UpdateProfileError(profileState.httpStatus)}
                        correlationId={profileState.correlationId}
                    />
                </Stack>
            ) : (
                <Typography variant="body2" sx={{ color: 'text.secondary', p: 2 }}>Loading...</Typography>
            )}
            <AppDialog
                open={showSuccessDialog}
                onClose={handleSuccessDialogClose}
                hideCloseButton
                title={
                    <Stack direction="row" spacing={1} sx={{ alignItems: 'center' }}>
                        <CheckCircleIcon sx={{ color: 'success.main' }} />
                        <Typography component="span" variant="h6">Profile Updated</Typography>
                    </Stack>
                }
                actions={
                    <Button variant="contained" onClick={handleSuccessDialogClose} autoFocus>
                        {profileId ? 'Close' : 'View Profile'}
                    </Button>
                }
            >
                <Typography variant="body2">
                    {profileId ? 'Profile was updated successfully.' : 'Your profile was updated successfully.'}
                </Typography>
            </AppDialog>
        </PageCard>
    )
}

