import { ProfileType, Roles } from "./api.types";

// ProfileView returned by the backend (fields are nullable per backend DTO).
export type PublicProfileResult = {
    id: string;
    name?: string;
    gender?: string;
    isContactInfoVisible: boolean;
    email?: string;
    phone?: string;
    location?: string;
    photo?: string;
    profileType?: string;
    entryYear: number;
    entryClass: number;
    exitYear: number;
    exitClass: number;
    batch: number;
    firstJnvId: number;
    firstJnvName?: string;
    otherJnvIds: number[];
    otherJnvNames: string[];
    isHigherEducationInfoVisible: boolean;
    isStudying: boolean;
    university?: string;
    degree?: string;
    isEmploymentInfoVisible: boolean;
    isWorking: boolean;
    organisation?: string;
    jobTitle?: string;
};

export type ProfileResult = PublicProfileResult & {
    createdAt?: number;
    modifiedAt?: number;
    createdBy?: string;
    createdByName?: string;
    modifiedBy?: string;
    latitude: number;
    longitude: number;
    roles?: Roles[];
};

export type ProfileBasicResult = {
    id: string;
    name?: string;
    batch: number;
    phone?: string;
    email?: string;
    firstJnvId: number;
    firstJnvName?: string;
    roles?: Roles[];
};

export type BaseProfilePayload = {
    name: string;
    gender: string;
    isContactInfoVisible: boolean;
    phone: string;
    location: string;
    latitude: number;
    longitude: number;
    profileType: ProfileType;
    entryYear: number;
    entryClass: number;
    exitYear: number;
    exitClass: number;
    firstJnvId: number;
    otherJnvIds: number[];
    isHigherEducationInfoVisible: boolean;
    isStudying: boolean;
    university: string;
    degree: string;
    isEmploymentInfoVisible: boolean;
    isWorking: boolean;
    organisation: string;
    jobTitle: string;
};

export type CreateProfilePayload = BaseProfilePayload & {
    email: string;
};

// PATCH /profile/me applies JSON Merge Patch — all fields optional.
export type UpdateProfilePayload = Partial<BaseProfilePayload> & {
    id?: string;
    email?: string;
};

export type ProfileGeoUpdatePayload = {
    latitude: number;
    longitude: number;
};

// Advanced field-specific search. Only the populated field is used as the search key.
export type AdvancedSearchProfilePayload = {
    pageNumber?: number;
    pageSize?: number;
    continuationToken?: string;
    searchText?: string;
    schoolName?: string;
    entryYear?: number;
    exitYear?: number;
    name?: string;
    location?: string;
    organisation?: string;
    jobTitle?: string;
    university?: string;
    degree?: string;
    phone?: string;
    email?: string;
};

const castBaseProfilePayload = (data: ProfileResult): BaseProfilePayload => ({
    name: data.name ?? '',
    gender: data.gender ?? '',
    isContactInfoVisible: data.isContactInfoVisible ?? false,
    phone: data.phone ?? '',
    location: data.location ?? '',
    latitude: data.latitude ?? 0,
    longitude: data.longitude ?? 0,
    profileType: (data.profileType as ProfileType) ?? ProfileType.Alumni,
    entryYear: data.entryYear ?? 0,
    entryClass: data.entryClass ?? 0,
    exitYear: data.exitYear ?? 0,
    exitClass: data.exitClass ?? 0,
    firstJnvId: data.firstJnvId ?? 0,
    otherJnvIds: data.otherJnvIds ?? [],
    isHigherEducationInfoVisible: data.isHigherEducationInfoVisible ?? false,
    isStudying: data.isStudying ?? false,
    university: data.university ?? '',
    degree: data.degree ?? '',
    isEmploymentInfoVisible: data.isEmploymentInfoVisible ?? false,
    isWorking: data.isWorking ?? false,
    organisation: data.organisation ?? '',
    jobTitle: data.jobTitle ?? '',
});

export const CastedUpdateProfilePayload = (data: ProfileResult): UpdateProfilePayload => ({
    ...castBaseProfilePayload(data),
    id: data.id,
    email: data.email ?? '',
});

export const CastedCreateProfilePayload = (data: ProfileResult): CreateProfilePayload => ({
    ...castBaseProfilePayload(data),
    email: data.email ?? '',
});
